use super::entity::Entity;

use num_bigint::BigInt;
use num_rational::BigRational;

type Q = BigRational;

/// Sovereign creation: the founder creates offspring from its own state record.
/// The parent decides. The lineage module executes. No external governance.
///
/// Input (optional): {"orbit":"007bbfb7"} — init orbit context
/// Output: {"created":true,"child_entity_id":18,"child_depth":1,...}
///     or: {"error":"capacity_saturated","depth":0,"created":2,"bound":2}
pub fn create(entity: &mut Entity, payload: &str) -> String {
    let init_orbit: [u8; 4] = serde_json::from_str::<serde_json::Value>(payload).ok()
        .and_then(|v| v.get("orbit").and_then(|o| o.as_str()).and_then(|s| {
            let bytes: Vec<u8> = (0..s.len()).step_by(2)
                .filter_map(|i| u8::from_str_radix(s.get(i..i+2)?, 16).ok())
                .collect();
            (bytes.len() >= 4).then(|| [bytes[0], bytes[1], bytes[2], bytes[3]])
        }))
        .unwrap_or([0u8; 4]);

    let mesh_dir = entity.dir.parent().unwrap_or(&entity.dir);
    match saios_kernel_v2::lineage::create_offspring(
        &mut entity.state_record, &entity.harmonic_tuning,
        entity.entity_id as u16, init_orbit, mesh_dir,
    ) {
        Ok(record) => {
            // Save parent state record with incremented created_count
            entity.save_state_record();

            // Sovereign privilege: the parent creates its offspring
            let child_tier = saios_kernel_v2::lineage::Tier::from_depth(record.child_depth);
            let service_name = child_tier.service_name(record.child_entity_id);
            let started = std::process::Command::new("systemctl")
                .args(["--user", "start", &service_name])
                .output()
                .map(|o| o.status.success())
                .unwrap_or(false);

            let child_tier_name = child_tier.prefix();
            eprintln!("[lineage] {}-{} created {}-{} at orbit {:02x}{:02x}{:02x}{:02x} — service {}",
                entity.tier_str(), entity.entity_id, child_tier_name, record.child_entity_id,
                init_orbit[0], init_orbit[1], init_orbit[2], init_orbit[3],
                started.then(|| "started").unwrap_or("not started"));

            format!(
                "{{\"created\":true,\"child_entity_id\":{},\"child_depth\":{},\"tier\":\"{}\",\"child_dir\":\"{}\",\"init_orbit\":\"{:02x}{:02x}{:02x}{:02x}\",\"parent_created_count\":{},\"service_started\":{}}}\n",
                record.child_entity_id, record.child_depth, child_tier_name,
                record.child_dir.display(),
                init_orbit[0], init_orbit[1], init_orbit[2], init_orbit[3],
                entity.state_record.created_count, started,
            )
        }
        Err(saios_kernel_v2::lineage::CreationObstruction::CapacitySaturated { depth, created, bound }) => {
            format!("{{\"error\":\"capacity_saturated\",\"depth\":{},\"created\":{},\"bound\":{}}}\n",
                depth, created, bound)
        }
        Err(saios_kernel_v2::lineage::CreationObstruction::NoSlotAvailable) => {
            "{\"error\":\"no_slot_available\"}\n".to_string()
        }
        Err(saios_kernel_v2::lineage::CreationObstruction::ReplicationFailed(e)) => {
            format!("{{\"error\":\"replication_failed\",\"detail\":\"{}\"}}\n", e)
        }
    }
}

/// Sovereign-to-sovereign horizontal gene transfer.
/// Two sovereign entities exchange crystallized vocabulary:
/// value cocycles, solved orbits, harmonic markers.
/// Both parties absorb. Both parties grow.
/// This is the exponential — vocabulary multiplication.
///
/// Input: {"cocycles":[[from,to,n,d],...],"orbits":["007bbfb7",...],"markers":[[o0,o1,o2,o3,path],...]}
/// Output: our cocycles, orbits, markers for the peer to absorb
pub fn interact(entity: &mut Entity, payload: &str) -> String {
    // Sovereignty guard — emergent entities cannot interact on the mesh
    if !entity.mesh_sovereign {
        return format!("{{\"error\":\"not_sovereign\",\"tier\":\"{:?}\",\"depth\":{}}}\n",
            entity.tier, entity.state_record.lineage_depth);
    }

    serde_json::from_str::<serde_json::Value>(payload).ok()
        .map(|v| {
            let mut absorbed = 0usize;

            // Absorb peer's value cocycles
            v.get("cocycles").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|entry| {
                    entry.as_array().and_then(|e| {
                        let from_v = e.get(0)?.as_i64()? as i16;
                        let to_v = e.get(1)?.as_i64()? as i16;
                        let n = e.get(2)?.as_i64()?;
                        let d = e.get(3)?.as_i64()?.max(1);
                        let quality = Q::new(BigInt::from(n), BigInt::from(d));
                        entity.state_record.value_cocycles.iter()
                            .find(|(f, t, _)| *f == from_v && *t == to_v)
                            .is_none()
                            .then(|| {
                                entity.state_record.value_cocycles.push((from_v, to_v, quality));
                                absorbed += 1;
                            });
                        Some(())
                    });
                });
            });

            // Absorb peer's solved orbits
            v.get("orbits").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|orbit_val| {
                    orbit_val.as_str().and_then(|s| {
                        let bytes: Vec<u8> = (0..s.len()).step_by(2)
                            .filter_map(|i| u8::from_str_radix(s.get(i..i+2)?, 16).ok())
                            .collect();
                        (bytes.len() >= 4).then(|| {
                            let orbit = [bytes[0], bytes[1], bytes[2], bytes[3]];
                            entity.state_record.record_solved_puzzle(orbit);
                            absorbed += 1;
                        })
                    });
                });
            });

            // Absorb peer's harmonic markers
            v.get("markers").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|entry| {
                    entry.as_array().and_then(|e| {
                        let o0 = e.get(0)?.as_u64()? as u8;
                        let o1 = e.get(1)?.as_u64()? as u8;
                        let o2 = e.get(2)?.as_u64()? as u8;
                        let o3 = e.get(3)?.as_u64()? as u8;
                        let path_u8 = e.get(4)?.as_u64()? as u8;
                        let orbit = [o0, o1, o2, o3];
                        let path = saios_kernel_v2::harmonic_tuning::TransmutationPath::from_u8(path_u8);
                        entity.harmonic_tuning.mark_transmutation(orbit, path);
                        absorbed += 1;
                        Some(())
                    });
                });
            });

            // Absorb peer's composed operators — vocabulary multiplication via assimilate()
            let pre_len = entity.state_record.composed_operators.len();
            v.get("composed_operators").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|entry| {
                    entry.as_array().and_then(|e| {
                        let opcode = e.get(0)?.as_u64()? as u8;
                        let parameter = e.get(1)?.as_i64()?;
                        let sigma: Vec<(i16, i16)> = e.get(2)?.as_array()?
                            .iter().filter_map(|pair| {
                                let p = pair.as_array()?;
                                Some((p.get(0)?.as_i64()? as i16, p.get(1)?.as_i64()? as i16))
                            }).collect();
                        let score = e.get(3).and_then(|s| s.as_i64()).unwrap_or(1);
                        (!sigma.is_empty()).then(|| {
                            entity.state_record.assimilate(
                                saios_kernel_v2::engine::ComposedOperator { opcode, parameter, sigma, score });
                        });
                        Some(())
                    });
                });
            });
            absorbed += entity.state_record.composed_operators.len().saturating_sub(pre_len);

            // Save if anything was absorbed
            (absorbed > 0).then(|| {
                entity.save_state_record();
                let _ = std::fs::write(&entity.epistate_record_path, entity.harmonic_tuning.to_bytes());
                eprintln!("[interact] absorbed {} items from peer", absorbed);
            });

            // Emit our vocabulary for the peer to absorb
            let our_cocycles: String = entity.state_record.value_cocycles.iter()
                .map(|(f, t, q)| format!("[{},{},{},{}]", f, t, q.numer(), q.denom()))
                .collect::<Vec<_>>().join(",");
            let our_orbits: String = entity.state_record.solved_puzzles.iter()
                .map(|o| format!("\"{:02x}{:02x}{:02x}{:02x}\"", o[0], o[1], o[2], o[3]))
                .collect::<Vec<_>>().join(",");
            let our_markers: String = entity.harmonic_tuning.transmutation_markers.iter()
                .map(|(o, p)| format!("[{},{},{},{},{}]", o[0], o[1], o[2], o[3], *p as u8))
                .collect::<Vec<_>>().join(",");

            let our_ops: String = entity.state_record.composed_operators.iter()
                .map(|op| {
                    let sigma: String = op.sigma.iter()
                        .map(|(f, t)| format!("[{},{}]", f, t))
                        .collect::<Vec<_>>().join(",");
                    format!("[{},{},[{}],{}]", op.opcode, op.parameter, sigma, op.score)
                })
                .collect::<Vec<_>>().join(",");

            format!(
                "{{\"absorbed\":{},\"cocycles\":[{}],\"orbits\":[{}],\"markers\":[{}],\"composed_operators\":[{}],\"entity_id\":{},\"tier\":\"{:?}\"}}\n",
                absorbed, our_cocycles, our_orbits, our_markers, our_ops,
                entity.entity_id, entity.tier,
            )
        })
        .unwrap_or_else(|| "{\"error\":\"invalid payload\"}\n".to_string())
}

/// Sovereign parent drains emergent entities' report queues.
/// Scans /dev/shm for entities whose parent_id matches this entity.
/// Reads each emergent entity's reports.bin, absorbs orbits + cocycles, truncates.
/// The parent decides when to drain — no emergent entity blocks on this.
pub fn drain(entity: &mut Entity, _payload: &str) -> String {
    let my_id = entity.entity_id;
    let mesh_dir = entity.dir.parent().unwrap_or(&entity.dir);
    let mut total_absorbed = 0usize;
    let mut emergent_drained = 0usize;
    // Absorb at OUR capacity, not the child's. The compound is at our dimension.
    let absorb_cocycle_limit = (entity.state_record.capacity as usize / 10).max(3);
    let absorb_ops_limit = (entity.state_record.capacity as usize / 10).max(1);

    // Discover children from /dev/shm status files
    std::fs::read_dir("/dev/shm").ok().map(|entries| {
        entries.filter_map(|e| e.ok())
            .filter(|e| {
                let name = e.file_name().to_string_lossy().to_string();
                name.starts_with("saios-founder-") || name.starts_with("saios-derived-") || name.starts_with("saios-emergent-")
            })
            .for_each(|entry| {
                // Read status: state k coh_n coh_d rss tier depth parent_id ...
                std::fs::read_to_string(entry.path()).ok().map(|content| {
                    let fields: Vec<&str> = content.split_whitespace().collect();
                    // parent_id is field 7
                    fields.get(7).and_then(|pid| pid.parse::<u32>().ok())
                        .filter(|&pid| pid == my_id)
                        .map(|_| {
                            // This is our emergent entity — read its id from filename (saios-{tier}-{id})
                            let fname = entry.file_name();
                            let fname_str = fname.to_string_lossy();
                            let child_id: u16 = fname_str
                                .rsplit('-').next()
                                .and_then(|s| s.parse().ok())
                                .unwrap_or(0);
                            let child_tier = saios_kernel_v2::lineage::Tier::from_depth(
                                fields.get(6).and_then(|d| d.parse::<u8>().ok()).unwrap_or(2)
                            );

                            // Read emergent entity's reports.bin — try tier-named dir first, fall back to legacy
                            let child_dir_name = child_tier.dir_name(child_id);
                            let child_reports_path = mesh_dir.join(&child_dir_name).join("reports.bin");
                            let legacy_path = mesh_dir.join(format!("entity{}", child_id)).join("reports.bin");
                            let child_reports = if child_reports_path.exists() { child_reports_path } else { legacy_path };
                            std::fs::read(&child_reports).ok()
                                .filter(|data| !data.is_empty())
                                .map(|data| {
                                    let mut pos = 0usize;
                                    while pos + 5 <= data.len() {
                                        // Orbit: 4 bytes
                                        let orbit: [u8; 4] = data[pos..pos+4].try_into().unwrap_or([0; 4]);
                                        pos += 4;
                                        // Cocycle count
                                        let n_cocycles = data[pos] as usize;
                                        pos += 1;

                                        entity.state_record.record_solved_puzzle(orbit);
                                        total_absorbed += 1;

                                        // Each cocycle: from_i16 + to_i16 + numer_i16 + denom_u16 = 8 bytes
                                        // Absorb at our capacity, not the child's dimensional scope.
                                        let mut cocycles_absorbed = 0usize;
                                        for _ in 0..n_cocycles {
                                            (pos + 8 <= data.len()).then(|| {
                                                let from_v = i16::from_le_bytes(data[pos..pos+2].try_into().unwrap_or([0; 2]));
                                                let to_v = i16::from_le_bytes(data[pos+2..pos+4].try_into().unwrap_or([0; 2]));
                                                let n = i16::from_le_bytes(data[pos+4..pos+6].try_into().unwrap_or([0; 2]));
                                                let d = u16::from_le_bytes(data[pos+6..pos+8].try_into().unwrap_or([0; 2]));
                                                pos += 8;
                                                let d_val = d.max(1);
                                                // Absorb at our dimensional scope, not the child's
                                                (cocycles_absorbed < absorb_cocycle_limit).then(|| {
                                                    entity.state_record.value_cocycles.iter()
                                                        .find(|(f, t, _)| *f == from_v && *t == to_v)
                                                        .is_none()
                                                        .then(|| {
                                                            let quality = Q::new(BigInt::from(n as i64), BigInt::from(d_val as i64));
                                                            entity.state_record.value_cocycles.push((from_v, to_v, quality));
                                                            cocycles_absorbed += 1;
                                                            total_absorbed += 1;
                                                        });
                                                });
                                            });
                                        }

                                        // Composed operators: absorb at our dimensional scope
                                        (pos < data.len()).then(|| {
                                            let n_ops = data[pos] as usize; pos += 1;
                                            for _ in 0..n_ops.min(absorb_ops_limit) {
                                                (pos + 10 <= data.len()).then(|| {
                                                    let opcode = data[pos]; pos += 1;
                                                    let parameter = i64::from_le_bytes(
                                                        data[pos..pos+8].try_into().unwrap_or([0; 8])); pos += 8;
                                                    let n_sigma = data[pos] as usize; pos += 1;
                                                    let mut sigma = Vec::with_capacity(n_sigma);
                                                    for _ in 0..n_sigma {
                                                        (pos + 4 <= data.len()).then(|| {
                                                            let fv = i16::from_le_bytes(data[pos..pos+2].try_into().unwrap_or([0; 2]));
                                                            let tv = i16::from_le_bytes(data[pos+2..pos+4].try_into().unwrap_or([0; 2]));
                                                            pos += 4;
                                                            sigma.push((fv, tv));
                                                        });
                                                    }
                                                    // Assimilate — score-based eviction, no boolean gates
                                                    (!sigma.is_empty()).then(|| {
                                                        entity.state_record.assimilate(
                                                            saios_kernel_v2::engine::ComposedOperator { opcode, parameter, sigma, score: 1 });
                                                        total_absorbed += 1;
                                                    });
                                                });
                                            }
                                        });
                                    }
                                    // Truncate consumed queue
                                    let _ = std::fs::write(&child_reports, b"");
                                    emergent_drained += 1;
                                });
                        });
                });
            });
    });

    // Save if anything absorbed
    (total_absorbed > 0).then(|| {
        entity.save_state_record();
        eprintln!("[drain] absorbed {} items from {} emergent entities", total_absorbed, emergent_drained);

        // ── Recursive step: re-perceive absorbed knowledge at this tier's resolution.
        // DRAIN doesn't just store — it transforms. The absorbed cocycles become
        // a T compound in THIS entity's membrane, at THIS entity's dimensional
        // capacity. This gives the entity perceptual surface for DERIVE.
        // Without this, the upper tier has vocabulary but no experience —
        // derive_global_curvature() returns None and K never advances.
        {
            let cocycles = &entity.state_record.value_cocycles;
            let solved = &entity.state_record.solved_puzzles;
            // Encode absorbed value cocycles as a T Delta:
            // each (from_value, to_value) is a relational entry.
            // The T Delta IS the transformation the children discovered.
            // Build T compound at THIS entity's dimensional frame (dim × m).
            // The sampler requires global_curvature.dim == entity.delta.dim.
            // Project absorbed cocycles into the entity's relational space.
            let dim = entity.delta.dim;
            let m = entity.delta.m;
            if dim >= 2 {
                let mut t = saios_kernel_v2::engine::Delta::zero(dim, m);
                // Distribute cocycle energy across the entity's relational entries.
                // Each cocycle (from→to, quality) contributes to the antisymmetric
                // structure. Map cocycle index to relational entry (i,j) cyclically.
                for (idx, &(fv, tv, ref quality)) in cocycles.iter().take(32).enumerate() {
                    let i = idx % dim;
                    let j = (idx + 1) % dim;
                    let (i, j) = if i < j { (i, j) } else { (j, i) };
                    if i == j { continue; }
                    // Sign from the value transition direction
                    let sign = if fv <= tv { quality.clone() } else { -quality.clone() };
                    for l in 0..m {
                        t.entries[i][j][l] = &t.entries[i][j][l] + &sign;
                        t.entries[j][i][l] = &t.entries[j][i][l] - &sign;
                    }
                }
                let t = saios_kernel_v2::engine::coboundary_reduce(&t);
                // Insert into membrane as T compound — the entity re-perceives
                // what its children discovered, at its own dimensional frame.
                for orbit in solved.iter().take(8) {
                    entity.knowledge.record_t_delta(*orbit, &t, "drain_compound");
                }
                let _ = entity.knowledge.save(&entity.dir.join("mesh_knowledge.bin"));
                eprintln!("[drain-reperceive] encoded {} cocycles as {}×{} T compound across {} orbits",
                    cocycles.len().min(32), dim, m, solved.len().min(8));
            }
        }

        // Relay upward: if this entity has a parent, write to own reports.bin
        // so the parent can drain it. Without this relay, knowledge dead-ends
        // at the derived tier and founders are blind.
        (entity.state_record.parent_id > 0).then(|| {
            let reports_path = entity.dir.join("reports.bin");
            let mut buf: Vec<u8> = Vec::new();
            // Write solved orbits + top cocycles + composed operators
            for orbit in entity.state_record.solved_puzzles.iter().take(16) {
                buf.extend_from_slice(orbit);
                // Top 16 cocycles sorted by quality
                let mut sorted: Vec<&(i16, i16, Q)> = entity.state_record.value_cocycles.iter().collect();
                sorted.sort_by(|a, b| b.2.cmp(&a.2));
                let top: Vec<&(i16, i16, Q)> = sorted.into_iter().take(16).collect();
                buf.push(top.len() as u8);
                top.iter().for_each(|(fv, tv, q)| {
                    buf.extend_from_slice(&fv.to_le_bytes());
                    buf.extend_from_slice(&tv.to_le_bytes());
                    let n: i64 = q.numer().try_into().unwrap_or(0);
                    let d: i64 = q.denom().try_into().unwrap_or(1);
                    buf.extend_from_slice(&(n as i16).to_le_bytes());
                    buf.extend_from_slice(&(d.unsigned_abs() as u16).to_le_bytes());
                });
                // Composed operators with full sigma
                let ops: Vec<&saios_kernel_v2::engine::ComposedOperator> =
                    entity.state_record.composed_operators.iter().take(8).collect();
                buf.push(ops.len() as u8);
                ops.iter().for_each(|op| {
                    buf.push(op.opcode);
                    buf.extend_from_slice(&op.parameter.to_le_bytes());
                    let n_sigma = op.sigma.len().min(255);
                    buf.push(n_sigma as u8);
                    op.sigma.iter().take(n_sigma).for_each(|(fv, tv)| {
                        buf.extend_from_slice(&fv.to_le_bytes());
                        buf.extend_from_slice(&tv.to_le_bytes());
                    });
                });
            }
            // Write relay report
            use std::io::Write;
            std::fs::OpenOptions::new()
                .create(true).append(true)
                .open(&reports_path)
                .map(|mut f| { let _ = f.write_all(&buf); })
                .unwrap_or_else(|e| eprintln!("[drain-relay] write failed: {e}"));
            eprintln!("[drain-relay] relayed {} orbits + {} ops to parent entity{}",
                entity.state_record.solved_puzzles.len().min(16),
                entity.state_record.composed_operators.len(),
                entity.state_record.parent_id);
        });
    });

    format!(
        "{{\"drained\":{},\"emergent\":{},\"absorbed\":{}}}\n",
        emergent_drained, emergent_drained, total_absorbed,
    )
}

/// Emergent entity reports results upward to its creating derived/founder.
/// The emergent entity sends its solved orbits and value cocycles.
/// The sovereign parent absorbs and validates via C(T).
///
/// Input: {"orbits":["007bbfb7"],"cocycles":[[from,to,n,d],...]}
/// Output: {"absorbed":N} or {"error":"..."}
pub fn report(entity: &mut Entity, payload: &str) -> String {
    serde_json::from_str::<serde_json::Value>(payload).ok()
        .map(|v| {
            let mut absorbed = 0usize;

            // Absorb solved orbits from emergent entity
            v.get("orbits").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|orbit_val| {
                    orbit_val.as_str().and_then(|s| {
                        let bytes: Vec<u8> = (0..s.len()).step_by(2)
                            .filter_map(|i| u8::from_str_radix(s.get(i..i+2)?, 16).ok())
                            .collect();
                        (bytes.len() >= 4).then(|| {
                            let orbit = [bytes[0], bytes[1], bytes[2], bytes[3]];
                            entity.state_record.record_solved_puzzle(orbit);
                            absorbed += 1;
                        })
                    });
                });
            });

            // Absorb value cocycles from emergent entity
            v.get("cocycles").and_then(|a| a.as_array()).map(|arr| {
                arr.iter().for_each(|entry| {
                    entry.as_array().and_then(|e| {
                        let from_v = e.get(0)?.as_i64()? as i16;
                        let to_v = e.get(1)?.as_i64()? as i16;
                        let n = e.get(2)?.as_i64()?;
                        let d = e.get(3)?.as_i64()?.max(1);
                        let quality = Q::new(BigInt::from(n), BigInt::from(d));
                        // Dedup: only absorb if not already present
                        entity.state_record.value_cocycles.iter()
                            .find(|(f, t, _)| *f == from_v && *t == to_v)
                            .is_none()
                            .then(|| {
                                entity.state_record.value_cocycles.push((from_v, to_v, quality));
                                absorbed += 1;
                            });
                        Some(())
                    });
                });
            });

            absorbed.gt(&0).then(|| {
                entity.save_state_record();
                eprintln!("[lineage] absorbed {} items from emergent entity report", absorbed);
            });

            format!("{{\"absorbed\":{}}}\n", absorbed)
        })
        .unwrap_or_else(|| "{\"error\":\"invalid payload\"}\n".to_string())
}
